import React, { useEffect, useState } from "react";
import { Link, NavLink } from 'react-router-dom';
import API from '../api/axios';
import "../style.css";
import heroImage from "../pic/h.jpg";

function HomePage() {
  const [darkMode, setDarkMode] = useState(false);
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .finally(() => setLoading(false));
  }, []);

  const toggleTheme = () => {
    setDarkMode(!darkMode);
  };

  useEffect(() => {
    const savedTheme = localStorage.getItem("theme");
    if (savedTheme === "dark") {
      setDarkMode(true);
    }
  }, []);

  useEffect(() => {
    if (darkMode) {
      document.body.classList.add("dark-mode");
      localStorage.setItem("theme", "dark");
    } else {
      document.body.classList.remove("dark-mode");
      localStorage.setItem("theme", "light");
    }
  }, [darkMode]);

  if (loading) return <p>Loading posts...</p>;

  return (
    <div>
      <header>
        <div className="logo">My Passion 💻</div>
        <nav>
          <ul className="nav-menu">
            <li><NavLink to="/home" className={({isActive}) => isActive ? "active" : ""}>Home</NavLink></li>
            <li><NavLink to="/about" className={({isActive}) => isActive ? "active" : ""}>About</NavLink></li>
            <li><NavLink to="/contact" className={({isActive}) => isActive ? "active" : ""}>Contact</NavLink></li>
            <li><NavLink to="/register" className={({isActive}) => isActive ? "active" : ""}>Register</NavLink></li>
          </ul>
        </nav>
      </header>

      <section className="hero">
        <div className="hero-text">
          <h1 style={{ textAlign: "center" }}>Welcome to My Portfolio</h1>
          <p style={{ textAlign: "center" }}>
            Exploring my passion for Coding
          </p>
        </div>

        <div className="hero-image">
          <img src={heroImage} alt="Featured topic" />
        </div>
      </section>

      <main>
        <div className="preview-container">
          <div className="preview">
            <h2>About My Journey</h2>
            <p>Learn how I got started with Coding and what inspires me.</p>
            <a href="/about">Read More →</a>
          </div>

          <div className="preview">
            <h2>Connect & Resources</h2>
            <p>Find useful resources and ways to reach out.</p>
            <a href="/contact">Explore →</a>
          </div>

          <div className="preview">
            <h2>Join the Community</h2>
            <p>Sign up to stay updated and share your interest.</p>
            <a href="/register">Register →</a>
          </div>
        </div>

        <section className="highlights">
          <h2>Key Highlights</h2>
          <ul>
            <li>Highlight 1 about Coding</li>
            <li>Highlight 2 about W3Schools</li>
            <li>Highlight 3 about Stack Overflow</li>
            <li>Highlight 4 about FreeCodeCamp</li>
          </ul>
        </section>

        <div className='home-page'>
          <h2>Latest Posts</h2>
          {posts.length === 0 ? (
            <p>No posts yet. Be the first to write one!</p>
          ) : (
            <div className='posts-grid'>
              {posts.map(post => (
                <div key={post._id} className='post-card'>
                  {post.image && (
                    <img src={`http://localhost:5000/uploads/${post.image}`} alt={post.title} />
                  )}
                  <h3><Link to={`/posts/${post._id}`}>{post.title}</Link></h3>
                  <p>{post.body.substring(0, 120)}...</p>
                  <small>By {post.author?.name} · {new Date(post.createdAt).toLocaleDateString()}</small>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      <button className="theme-toggle" onClick={toggleTheme}>
        {darkMode ? "☀️ Light Mode" : "🌙 Dark Mode"}
      </button>

      <footer>
        <p>Contact: email@example.com | Phone: (000) 000-0000</p>
        <p>© 2026 My Passion Portfolio</p>
      </footer>
    </div>
  );
}

export default HomePage;
